"use client";

import { useState, useEffect } from "react";

export default function PDFViewer({ page }: { page: number }) {
  const [pdfUrl, setPdfUrl] = useState<string | null>(null);
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, [page]);

  const uploadPDF = async (file: File) => {
    const formData = new FormData();
    formData.append("file", file);

    const res = await fetch("http://127.0.0.1:8000/upload", {
      method: "POST",
      body: formData,
    });

    if (res.ok) {
      const url = URL.createObjectURL(file);
      setPdfUrl(url);
    }
  };

  return (
    <main className="flex-1 bg-[#1e232e] p-6 flex flex-col">
      <h2 className="text-xl mb-4 text-white">PDF Viewer</h2>

      <input
        type="file"
        accept="application/pdf"
        onChange={(e) => {
          if (e.target.files) {
            uploadPDF(e.target.files[0]);
          }
        }}
        className="mb-4 text-white"
      />

      <div className="flex-1 bg-white rounded overflow-hidden">
        {pdfUrl ? (
          <iframe
            key={page}
            src={`${pdfUrl}#page=${page}`}
            className="w-full h-full"
          />
        ) : (
          <div className="flex items-center justify-center h-full text-black">
            Upload a PDF to begin
          </div>
        )}
      </div>
    </main>
  );
}


